        {
            // Arrange
            var valorQuemCad = 2500;
            var filtro = new FilterReuniao
            {
                QuemCad = valorQuemCad,
                QuemCad_end = int.MinValue, // Não define salário final
                LogicalOperator = " AND "
            };
            // Act
            var resultado = _serviceS.WFiltro(filtro);
